export function getStaticImage(query: string): string | null {
  const arr = STATIC_IMAGES[query];
  return arr && arr.length ? arr[0] : null;
}

export function getStaticImages(query: string): string[] {
  return STATIC_IMAGES[query] ?? [];
}
